460	                                path, pattern
461	                            ),
462	                            next_attempt_plan:
463	                                "Update the file so the required pattern is present before emitting checkpoint_success again."
464	                                    .to_string(),
465	                        }),
466	                    });
467	                }
468	            }
469	            orbit_common::types::TaskPlanSuccessCriterion::Semantic { .. } => {}
470	        }
471	    }
